site_id = #{siteId}, member_id = #{memberId}, member_nm = #{memberNm}, category_cd = #{categoryCd}, contact_title = #{contactTitle}, contact_content = #{contactContent}, attach_grp_id = #{attachGrpId}, contact_status_cd = #{contactStatusCd}, contact_answer = #{contactAnswer}, answer_user_id = #{answerUserId}, answer_date = #{answerDate}, contact_date = #{contactDate}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE contact_id = #{contactId}
